  //init the year month setting
  String yearmonth=report.getValue("ym");
//  Calendar now=new GregorianCalendar();
  int year=-1;
  int month=-1;

  //parse the report setting
  try{
    String[] yearMonthSec=yearmonth.split("/");
    year=Encoder.parseInt(yearMonthSec[0],-1);
    month=Encoder.parseInt(yearMonthSec[1],-1)-1;
  }
  catch(Exception e){
    yearmonth=year+"/"+(month+1);
  }

  //determine if all time
  boolean allTime=year==-1 && month==-1;

