  if(dateDomain==null || DConst.ENTRY_CREATE_DATE==Encoder.parseInt(dateDomain)) dateDomain="_create_date";
  NUIForm form=aq.getForm();
  List<CellInfo> factFields=form.getFactFields();
  List<CellInfo> selectionFields=form.getSelectionFields();
  List<CellInfo> textFields=form.getTextFields();
  List<CellInfo> dateFields=form.getTimeFields();
  CellInfo factField=form.getField(factDomainId);
  String decimalFormat=factField==null?"#,###.##":Encoder.unformatNUIAttr(factField.getAttribute("fmt_n"));
  RankingAdder rankingAdder=new RankingAdder(year,month);

  //find a default value for row domain
  if(rowDomainId==Const.NODOMAIN && selectionFields.size()>0){
    rowDomainId=selectionFields.get(0).getDomainId();
  }

  //row field aggregate
  CellInfo rowField=form.getField(rowDomainId);
  CategoryDate category=null;
  String rowAgg=null;
  if(rowField!=null && rowField.getAttribute("fmt_d")!=null){
    rowAgg=report.getValue("rowAgg");
    if(rowAgg==null) rowAgg="M";
    category=CategoryDate.getCategory(rowAgg);
  }


  //set the fetch domains for better performance
  aq.addFetchDomains(rowDomainId);
  aq.addFetchDomains(factDomainId);
  aq.addFetchDomains(Encoder.parseInt(dateDomain));


  Selection rowSelection=null;
  BDBWorker worker=new BDBWorker(aq.getApname());
  try{
    if(rowDomainId!=Const.NODOMAIN) rowSelection= DataHelper.createOption(rowDomainId, worker);
  }
  finally {
    worker.commit();
  }

  APIResultsFull ar = aq.getAPIResultsFull();
  for (APIEntry e : ar) {
    e.setIfTranslateEmailToUserName(true);

    List<String> rowValues=e.getFieldValues(rowDomainId);


    String dateValue=e.getFieldValue(dateDomain);
    String factValue=factDomainId==Const.NODOMAIN?"1":e.getFieldValue(factDomainId);
    for(String rowValue:rowValues){
      if(rowSelection!=null) {
        //match cascaded selection values
        if(rowSelection.isCascaded()){
          for(SDBNode node:rowSelection.getOptions()){
            if(node!=null && node.getValue()!=null && node.getValue().endsWith("|"+rowValue)){
              rowValue=node.getValue();
            }
          }
        }
        rowSelection.addOptionIfNotExist(rowValue);
      }

      //normalize date value
      if(category!=null){
        rowValue=category.categorize(rowValue);
      }

      rankingAdder.add(rowValue,dateValue,factValue);
    }
  }

  //choose year/month
  out.println("<div class='printHide' style='padding:12px 25px;background:#efefef;font-size:12px;'>");


