  out.println("<option value='-1/0'>"+bundle.getString("allTime")+"</option>");
  for(int iYear=2008;iYear<2016;iYear++){
    for(int iMonth=1;iMonth<=12;iMonth++){
      String ym=iYear+"/"+iMonth;
      out.println("<option value='"+ym+"' "+(ym.equals(yearmonth)?"selected":"")+">"+bundle.getString("month"+iMonth)+", "+iYear+"</option>");
    }
  }
